css:
.loader {color: var(--loader-color, #db2777);
  --loader-secondary-color: #f9a8d4;
  --loader-bg: #ffffff;
  display: inline-grid;
  width: 40px;
  aspect-ratio: 1;
}.loader:before,.loader:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
  background: repeating-conic-gradient(var(--loader-color, #db2777) 0 60deg,var(--loader-secondary-color, #f9a8d4) 0 120deg);
  animation: l7 2s infinite alternate ease-in-out;
  rotate: 90deg;
}.loader:before {translate: 0 -100%;
}.loader:after {padding: 20%;
  mask: conic-gradient(from 120deg,#0000 120deg,currentColor 0) content-box exclude,conic-gradient(from 120deg,#0000 120deg,currentColor 0);
  animation-direction: alternate-reverse;
}@keyframes l7 {to{rotate: -90deg;
}}
